import asyncio
import aiofiles

async def process_file(path: str) -> int:
    async with aiofiles.open(path) as f:
        content = await f.read()
    return len(content)

async def process_all(paths: list[str]) -> dict[str, int]:
    async with asyncio.TaskGroup() as tg:
        tasks = {path: tg.create_task(process_file(path)) for path in paths}
    return {path: task.result() for path, task in tasks.items()}

